class Solution(object):
    def maxNumberOfAlloys(self, n, k, budget, composition, stock, cost):
        def can_make(machine, amount):
            total_cost = 0
            for j in range(n):
                need = composition[machine][j] * amount
                have = stock[j]
                if need > have:
                    total_cost += (need - have) * cost[j]
                if total_cost > budget:
                    return False
            return total_cost <= budget

        ans = 0
        for m in range(k):
            lo, hi = 0, 10**9
            while lo <= hi:
                mid = (lo + hi) // 2
                if can_make(m, mid):
                    ans = max(ans, mid)
                    lo = mid + 1
                else:
                    hi = mid - 1
        return ans
